import requests
import json
import hmac
import hashlib
import os
from flask import current_app, abort

def func(api_endpoint, payload):
    api_key = os.getenv('API_KEY')
    api_secret = os.getenv('API_SECRET')

    if not api_key or not api_secret:
        abort(500, description="API credentials not configured.")

    # Generate a secure signature for the request
    signature = hmac.new(api_secret.encode(), json.dumps(payload).encode(), hashlib.sha256).hexdigest()

    headers = {
        'Content-Type': 'application/json',
        'Authorization': f'Bearer {api_key}',
        'X-Signature': signature
    }

    try:
        response = requests.post(api_endpoint, headers=headers, json=payload)
        response.raise_for_status()
    except requests.exceptions.HTTPError as http_err:
        abort(response.status_code, description=f"HTTP error occurred: {http_err}")
    except requests.exceptions.RequestException as req_err:
        abort(500, description=f"Request error occurred: {req_err}")

    return response.json()

