from contextlib import contextmanager
import logging
import os

DATABASE_URL = os.getenv("DATABASE_URL")

@contextmanager
def get_db_connection():
    engine = create_engine(DATABASE_URL)
    connection = engine.connect()
    try:
        yield connection
    except SQLAlchemyError as e:
        logging.error(f"Database error: {e}")
        connection.rollback()
        raise
    finally:
        connection.close()

def log_api_call(api_url, response_status):
    with get_db_connection() as conn:
        try:
            conn.execute(
                text("INSERT INTO api_call_logs (api_url, response_status) VALUES (:url, :status)"),
                {"url": api_url, "status": response_status}
            )
        except SQLAlchemyError as e:
            logging.error(f"Failed to log API call: {e}")

def func(api_endpoint):
    api_key = os.getenv("API_KEY")
    if not api_key:
        raise ValueError("API key is not configured.")

    headers = {"Authorization": f"Bearer {api_key}"}

    try:
        response = requests.get(api_endpoint, headers=headers, timeout=10)
        response.raise_for_status()
        log_api_call(api_endpoint, response.status_code)
        return response.json()
    except requests.RequestException as e:
        logging.error(f"API call failed: {e}")
        log_api_call(api_endpoint, 'failed')
        raise

import requests
import logging
import sqlite3
from contextlib import closing

DATABASE = 'secure_audit.db'
API_URL = 'https://api.example.com/data'

def func(user_id, api_key):
    if not is_valid_api_key(api_key):
        logging.warning("Invalid API key for user: %s", user_id)
        return {"error": "Unauthorized"}, 401

    with closing(sqlite3.connect(DATABASE)) as conn:
        with closing(conn.cursor()) as cursor:
            cursor.execute("SELECT last_access_time FROM users WHERE user_id = ?", (user_id,))
            user_data = cursor.fetchone()
            if user_data is None:
                logging.warning("User not found: %s", user_id)
                return {"error": "User not found"}, 404

            last_access_time = user_data[0]
            if has_accessed_recently(last_access_time):
                response = requests.get(API_URL, headers={"Authorization": f"Bearer {api_key}"})
                if response.status_code == 200:
                    logging.info("API call successful for user: %s", user_id)
                    return response.json(), 200
                else:
                    logging.error("API call failed for user: %s, status code: %d", user_id, response.status_code)
                    return {"error": "Failed to retrieve data"}, response.status_code
            else:
                logging.warning("User accessed API too frequently: %s", user_id)
                return {"error": "Access denied: Rate limit exceeded"}, 429

def is_valid_api_key(api_key):
    return len(api_key) == 32 and api_key.isalnum()

def has_accessed_recently(last_access_time):
    # Check if the last access time is within the allowed period, for example, 1 hour.
    from datetime import datetime, timedelta
    return datetime.now() < datetime.strptime(last_access_time, '%Y-%m-%d %H:%M:%S') + timedelta(hours=1)

