                return {"status": "error", "message": "API call too frequent."}

        response = requests.get(API_ENDPOINT, headers={"Authorization": f"Bearer {API_KEY}"})

        if response.status_code == 200:
            data = response.json()
            conn.execute(text("UPDATE users SET last_api_call = :current_time WHERE id = :user_id"), 
                         {'current_time': time.time(), 'user_id': user_id})
            return {"status": "success", "data": data}
        else:
            logging.error(f"API call failed with status code {response.status_code}")
            return {"status": "error", "message": "Failed to retrieve data from third-party API."}

