def setup_logging():
    logging.basicConfig(filename=LOG_FILE, level=logging.INFO, format='%(asctime)s:%(levelname)s:%(message)s')

def func(user_id, query_param):
    setup_logging()
    engine = create_engine(DATABASE_URL)

    with engine.connect() as connection:
        result = connection.execute(text("SELECT api_key FROM users WHERE id = :user_id"), {"user_id": user_id})
        api_key_row = result.fetchone()
        if not api_key_row:
            logging.warning(f"User ID {user_id} not found.")
            return {"error": "User not found."}

        api_key = api_key_row[0]

    headers = {
        'Authorization': f'Bearer {api_key}',
        'Content-Type': 'application/json'
    }
    payload = {'query': query_param}

    try:
        response = requests.post(API_URL, headers=headers, json=payload)
        response.raise_for_status()
    except requests.exceptions.RequestException as e:
        logging.error(f"API call failed: {e}")
        return {"error": "API call failed."}

    data = response.json()
    try:
        with engine.connect() as connection:
