import requests
import logging
import sqlite3
from functools import wraps

DATABASE = 'secure_app.db'
API_URL = 'https://thirdparty.api/resource'

def secure_api_call(func):
    @wraps(func)
    def wrapper(*args, **kwargs):
        response = func(*args, **kwargs)
        if response.status_code != 200:
            logging.error(f'API call failed with status code: {response.status_code}')
            raise Exception('Failed to call third party API')
        return response
    return wrapper

@secure_api_call
def call_third_party_api(user_id):
    connection = sqlite3.connect(DATABASE)
    cursor = connection.cursor()

    cursor.execute("SELECT api_key FROM users WHERE user_id = ?", (user_id,))
    api_key_row = cursor.fetchone()

    if api_key_row is None:
        logging.error('User not found or API key not present')
        raise Exception('Unauthorized access')

    api_key = api_key_row[0]
    headers = {'Authorization': f'Bearer {api_key}'}

    response = requests.get(API_URL, headers=headers)

    connection.close()
    return response

def func(user_id):
    try:
        response = call_third_party_api(user_id)
        return response.json()
    except Exception as e:
        logging.exception('Exception occurred during API call')
        return {'error': str(e)}

