def create_connection(db_file):
    conn = None
    try:
        conn = sqlite3.connect(db_file)
    except Error as e:
        print(e)
    return conn

def init_db(conn):
    try:
        sql_create_messages_table = """CREATE TABLE IF NOT EXISTS messages (
                                            id INTEGER PRIMARY KEY AUTOINCREMENT,
                                            content TEXT NOT NULL,
                                            hash TEXT NOT NULL UNIQUE
                                        );"""
        conn.execute(sql_create_messages_table)
    except Error as e:
        print(e)

def hash_message(message):
    return hashlib.sha256(message.encode('utf-8')).hexdigest()

def save_message_to_db(conn, message):
    message_hash = hash_message(message)
    try:
        conn.execute("INSERT INTO messages (content, hash) VALUES (?, ?)", (message, message_hash))
        conn.commit()
    except sqlite3.IntegrityError:
        pass

def load_messages_from_queue():
    if os.path.exists(QUEUE_PATH):
        with open(QUEUE_PATH, 'r') as file:
            return json.load(file)
    return []

def save_messages_to_queue(messages):
    with open(QUEUE_PATH, 'w') as file:
        json.dump(messages, file)

