    return role in ['admin', 'superuser']

def fetch_environment_config(env_name, user_id):
    role = get_user_role(user_id)
    if not is_authorized(role):
        raise PermissionError("User does not have access to configuration.")

    conn = sqlite3.connect(DATABASE_PATH)
    cursor = conn.cursor()
    cursor.execute("SELECT config_data FROM configurations WHERE env_name=?", (env_name,))
    result = cursor.fetchone()
    conn.close()

    if result:
        encrypted_data = result[0]
        return decrypt_config(encrypted_data)
    else:
        raise ValueError("Environment configuration not found.")

def func(env_name, user_id):
