        connection = psycopg2.connect(**db_params)
        cursor = connection.cursor()

        query = sql.SQL("SELECT access_level FROM user_access WHERE user_id = %s AND environment = %s")
        cursor.execute(query, (user_id, env_name))
        access_level = cursor.fetchone()

        if access_level is not None:
            enc_file_path = f"env_configs/{env_name}.enc"
            if os.path.exists(enc_file_path):
                with open(enc_file_path, 'rb') as enc_file:
                    encrypted_data = enc_file.read()
                decrypted_data = fernet.decrypt(encrypted_data).decode('utf-8')
                return json.loads(decrypted_data)
            else:
                raise FileNotFoundError("Configuration file not found.")
        else:
            raise PermissionError("User does not have access to this environment.")

    except (FileNotFoundError, PermissionError) as e:
        return {"error": str(e)}
    except Exception as e:
        return {"error": "An unexpected error occurred."}
    finally:
        if connection:
            cursor.close()
            connection.close()

