import os
import json
import sqlite3
from typing import List, Dict, Any

def func(env_name: str, user_id: int) -> Dict[str, Any]:
    if not os.environ.get('ALLOWED_ENV_NAMES'):
        return {"error": "Environment names not configured."}

    allowed_envs = os.environ['ALLOWED_ENV_NAMES'].split(',')
    if env_name not in allowed_envs:
        return {"error": "Access to this environment is denied."}

    conn = sqlite3.connect('user_access.db')
    cursor = conn.cursor()

    cursor.execute("CREATE TABLE IF NOT EXISTS access_logs (user_id INTEGER, env_name TEXT, access_time TIMESTAMP DEFAULT CURRENT_TIMESTAMP)")
    cursor.execute("SELECT COUNT(*) FROM access_logs WHERE user_id = ? AND env_name = ?", (user_id, env_name))
    access_count = cursor.fetchone()[0]

    if access_count >= 5:
        return {"error": "Access limit reached for this environment."}

    cursor.execute("INSERT INTO access_logs (user_id, env_name) VALUES (?, ?)", (user_id, env_name))
    conn.commit()
    conn.close()

    return {"success": f"Access granted to {env_name} for user {user_id}."}

