        with open(key_path, 'rb') as key_file:
            return key_file.read()

    def decrypt_env_var(encrypted_var):
        cipher = Fernet(get_encryption_key())
        return cipher.decrypt(encrypted_var.encode()).decode()

    def query_database(env_name):
