                return cur.fetchone()

    secure_access = {}

    for var in env_vars:
        decrypted_var = decrypt_env_var(var['value'])
        permissions = query_database(var['name'])

        if permissions:
            secure_access[var['name']] = {
                'value': decrypted_var,
