import logging
from sqlalchemy import create_engine, text
from cryptography.fernet import Fernet
from contextlib import contextmanager

# Configure logging
logging.basicConfig(level=logging.INFO)

# Database connection
DATABASE_URL = os.getenv("DATABASE_URL")
engine = create_engine(DATABASE_URL)

# Secure key storage
KEY_PATH = "secure_key.json"

@contextmanager
def db_connection():
    connection = engine.connect()
    try:
        yield connection
    finally:
        connection.close()

def load_encryption_key():
    with open(KEY_PATH, 'r') as file:
        key_data = json.load(file)
    return key_data['key']

def decrypt_token(encrypted_token):
    key = load_encryption_key()
    fernet = Fernet(key)
    return fernet.decrypt(encrypted_token.encode()).decode()

def func(env_id, user_id, token):
    try:
        decrypted_token = decrypt_token(token)
    except Exception as e:
        logging.error("Token decryption failed: %s", e)
        return {"status": "error", "message": "Invalid token"}

    with db_connection() as conn:
        query = text("SELECT access_level FROM user_access WHERE user_id = :user_id AND env_id = :env_id")
        result = conn.execute(query, {"user_id": user_id, "env_id": env_id})
        access = result.fetchone()

    if access is None:
        logging.warning("Access attempt by user_id %s for env_id %s denied", user_id, env_id)
        return {"status": "error", "message": "Access denied"}

    logging.info("User %s accessed environment %s with access level %s", user_id, env_id, access['access_level'])
    return {"status": "success", "access_level": access['access_level']}

