            id INTEGER PRIMARY KEY,
            name TEXT UNIQUE NOT NULL
        )
    ''')

    cursor.execute('''
        CREATE TABLE IF NOT EXISTS user_access (
            user_id INTEGER,
            env_id INTEGER,
            can_access BOOLEAN,
            FOREIGN KEY(env_id) REFERENCES environments(id)
        )
    ''')

