from cryptography.fernet import Fernet

def func(env_name):
    conn = None
    try:
        conn = psycopg2.connect(dbname='secure_db', user='user', password='password', host='localhost', port='5432')
        cursor = conn.cursor()

        cursor.execute(sql.SQL("SELECT access_level, config_data FROM env_configs WHERE env_name = %s"), [env_name])
        result = cursor.fetchone()

        if result:
            access_level, encrypted_data = result
            if access_level < 2:
                return json.dumps({"error": "Access denied."})

            key = os.environ.get('ENCRYPTION_KEY')
            fernet = Fernet(key)
            decrypted_data = fernet.decrypt(encrypted_data).decode()

            return json.dumps({"config_data": json.loads(decrypted_data)})

        return json.dumps({"error": "Environment not found."})

    except Exception as e:
        return json.dumps({"error": str(e)})

