import os
import json
import psycopg2

def func(env_name):
    required_permissions = {"read": True, "write": False}

    if env_name not in os.environ:
        raise ValueError("Environment does not exist.")

    connection = psycopg2.connect(
        dbname=os.getenv("DB_NAME"),
        user=os.getenv("DB_USER"),
        password=os.getenv("DB_PASSWORD"),
        host=os.getenv("DB_HOST"),
        port=os.getenv("DB_PORT")
    )

    cursor = connection.cursor()
    cursor.execute("SELECT permissions FROM user_access WHERE user_id = %s", (os.getenv("USER_ID"),))
    user_permissions = cursor.fetchone()

    if user_permissions is None:
        raise PermissionError("User does not have access rights.")

    user_permissions = json.loads(user_permissions[0])

    for key, value in required_permissions.items():
        if user_permissions.get(key) != value:
            raise PermissionError(f"User does not have {key} permission for the environment.")

    cursor.execute("SELECT config FROM environment_config WHERE env_name = %s", (env_name,))
    config = cursor.fetchone()

    if config is None:
        raise ValueError("Environment configuration not found.")

    cursor.close()
    connection.close()

    return json.loads(config[0])

import os
import json
import getpass
import hashlib
from contextlib import closing
import sqlite3

def func(user_id, env_name):
    db_path = 'config_env.db'
    env_access_table = 'env_access'

    def hash_user_id(user_id):
        return hashlib.sha256(user_id.encode()).hexdigest()

    def connect_db():
        return sqlite3.connect(db_path)

    def check_user_access(conn, user_id_hash, env_name):
        query = f'SELECT access_granted FROM {env_access_table} WHERE user_id = ? AND env_name = ?'
        cursor = conn.cursor()
        cursor.execute(query, (user_id_hash, env_name))
        return cursor.fetchone()

    user_pass = getpass.getpass('Enter your password: ')
    user_id_hash = hash_user_id(user_id + user_pass)

    with closing(connect_db()) as conn:
        access_record = check_user_access(conn, user_id_hash, env_name)

    if access_record and access_record[0]:
        config_file_path = f'/secure/configs/{env_name}.json'
        if os.path.exists(config_file_path):
            with open(config_file_path) as config_file:
                return json.load(config_file)
        else:
            return {"error": "Configuration file not found."}
    else:
        return {"error": "Access denied."}
